import { Link, withPrefix } from "gatsby";
import React from "react";
import { Image, Nav, Navbar } from "react-bootstrap";
import navbarlinks from "../../content/header.yaml";


export function NavLink(props) {
  return (
    <Nav.Link
      as={Link}
      to={props.to}
      className="nav-item"
      activeClassName="active active-link"
      // All other props
      {...props}>
      {props.children}
    </Nav.Link>
  );
}

function navLinks() {
  return navbarlinks.map((nav, idx) =>
    <NavLink to={nav.link} key={idx}>
      {nav.text}
    </NavLink>
  );
}

export function Header(props) {
  return (
    <Navbar expand="lg" className="io-navbar" >
      <Navbar.Brand href={withPrefix("/")}>
        <Image
          alt="IO Banner"
          src={withPrefix("/logos/cmyk/logo.webp")}
          height="30"
          className="d-inline-block align-top"
        />{" "}
        Insight Optics
      </Navbar.Brand>
      <Navbar.Toggle aria-controls="basic-navbar-nav" />
      <Navbar.Collapse id="basic-navbar-nav">
        <Nav fill className="ml-auto">
          {navLinks()}
        </Nav>
      </Navbar.Collapse>
    </Navbar>
  )
}
